34	@ApiTags('Auth')
35	@Throttle({ default: { limit: 10, ttl: 60000 } })
36	@Controller('auth')
37	export class AuthController {
38		constructor(private readonly authService: AuthService) {}
39	
40		@Public()
41		@Get('github')
42		@ApiOperation({ summary: 'Initiate GitHub OAuth' })
43		@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to GitHub' })
44		@LogExecution({ logResponse: false })
45		async githubAuth(@Res() reply: FastifyReply): Promise<void> {
46			const url = await this.authService.initiateOAuth({ provider: 'github' });
47			reply.status(HttpStatus.FOUND).redirect(url.toString());
48		}
49	
50		@Public()
51		@Get('github/callback')
52		@ApiOperation({ summary: 'Handle GitHub OAuth callback' })
53		@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
54		@LogExecution({ logParams: false, logResponse: false })
55		async githubCallback(
56			@Query('code') code: string,
57			@Query('state') state: string,
58			@Res() reply: FastifyReply,
59		): Promise<void> {
60			const result = await this.authService.handleCallback({
61				provider: 'github',
62				code,
63				state,
64			});
65			const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
66			if (result.type === 'auth_code') {
67				reply
68					.status(HttpStatus.FOUND)
69					.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
70			} else {
71				reply
72					.status(HttpStatus.FOUND)
73					.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
74			}
75		}
76	
