78		@Get('google')
79		@ApiOperation({ summary: 'Initiate Google OAuth' })
80		@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to Google' })
81		@LogExecution({ logResponse: false })
82		async googleAuth(@Res() reply: FastifyReply): Promise<void> {
83			const url = await this.authService.initiateOAuth({ provider: 'google' });
84			reply.status(HttpStatus.FOUND).redirect(url.toString());
