91		@LogExecution({ logParams: false, logResponse: false })
92		async googleCallback(
93			@Query('code') code: string,
94			@Query('state') state: string,
95			@Res() reply: FastifyReply,
96		): Promise<void> {
97			const result = await this.authService.handleCallback({
98				provider: 'google',
99				code,
100				state,
101			});
