114		@Public()
115		@Post('token')
116		@ApiOperation({ summary: 'Exchange auth code for JWT tokens' })
117		@ApiResponse({
118			status: HttpStatus.OK,
119			description: 'Returns access token, sets refresh cookie',
120		})
121		@LogExecution({ logParams: false, logResponse: false })
122		async exchangeToken(
123			@Body() dto: TokenExchangeDto,
124			@Req() request: FastifyRequest,
125			@Res() reply: FastifyReply,
126		): Promise<void> {
127			const result = await this.authService.exchangeCode({
128				code: dto.code,
129				ip: request.ip,
130				userAgent: request.headers['user-agent'] ?? '',
131				provider: 'github',
132			});
133	
134			reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
135				httpOnly: true,
136				secure: !isDevEnv(),
137				sameSite: 'strict',
138				path: '/api/auth',
139				maxAge: 30 * 24 * 60 * 60,
140			});
141	
142			reply.send({ access_token: result.accessToken });
143		}
144	
145		@Public()
146		@Throttle({ default: { limit: 5, ttl: 60000 } })
147		@Post('refresh')
148		@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
149		@ApiResponse({
150			status: HttpStatus.OK,
151			description: 'Returns new access token, rotates refresh cookie',
152		})
153		@ApiResponse({
154			status: HttpStatus.UNAUTHORIZED,
155			description: 'No or invalid refresh token',
156		})
157		@LogExecution({ logParams: false, logResponse: false })
158		async refresh(
159			@Req() request: FastifyRequest,
160			@Res() reply: FastifyReply,
161		): Promise<void> {
162			const refreshToken = (request.cookies as Record<string, string>)[
163				REFRESH_TOKEN_COOKIE_NAME
164			];
165			if (!refreshToken) throw new UnauthorizedException('No refresh token');
166	
167			const result = await this.authService.refreshTokens({ refreshToken });
168	
169			reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
170				httpOnly: true,
171				secure: !isDevEnv(),
172				sameSite: 'strict',
173				path: '/api/auth',
174				maxAge: 30 * 24 * 60 * 60,
175			});
176	
177			reply.send({ access_token: result.accessToken });
178		}
