206			@Body() dto: LinkAccountDto,
207			@CurrentUser() user: IRequestUser,
208		): Promise<{ success: boolean }> {
209			await this.authService.linkAccount({
210				linkingToken: dto.linking_token,
211				userId: user.user_id,
212			});
213			return { success: true };
214		}
215	
216		@Post('signup/company')
217		@ApiOperation({ summary: 'Create a company for the current user' })
218		@ApiResponse({
219			status: HttpStatus.CREATED,
220			description: 'Company created successfully',
221		})
222		@LogExecution()
223		async createCompany(
224			@Body() dto: CreateCompanyDto,
225			@CurrentUser() user: IRequestUser,
226		): Promise<{ company_id: string }> {
227			return this.authService.createCompany({
228				name: dto.name,
229				userId: user.user_id,
230				sessionId: user.session_id,
231			});
232		}
233	}
