31	interface IOAuthState {
32		codeVerifier: string;
33		provider: 'github' | 'google';
34		invitationToken?: string;
35	}
36	
37	@Injectable()
38	export class AuthService {
39		private readonly logger = new Logger(AuthService.name);
40	
41		constructor(
42			private readonly githubStrategy: GithubStrategy,
43			private readonly googleStrategy: GoogleStrategy,
44			private readonly userService: UserService,
45			private readonly oauthAccountService: OAuthAccountService,
46			private readonly companyMemberService: CompanyMemberService,
47			private readonly companyService: CompanyService,
48			private readonly sessionService: SessionService,
49			private readonly jwtService: JwtService,
50			private readonly configService: EnvConfigService,
51			@Inject(REDIS_WRITE_CLIENT) private readonly redisWrite: Redis,
52		) {}
53	
54		private getStrategy({
55			provider,
56		}: {
57			provider: 'github' | 'google';
58		}): GithubStrategy | GoogleStrategy {
59			if (provider === 'github') {
60				return this.githubStrategy;
61			}
62			return this.googleStrategy;
63		}
64	
65		async initiateOAuth({
66			provider,
67			invitationToken,
68		}: {
69			provider: 'github' | 'google';
70			invitationToken?: string;
71		}): Promise<URL> {
72			this.logger.log('Initiating OAuth', { provider });
73	
74			const state = randomBytes(32).toString('hex');
75			const codeVerifier = generateCodeVerifier();
76	
77			const stateData: IOAuthState = { codeVerifier, provider };
78			if (invitationToken !== undefined) {
79				stateData.invitationToken = invitationToken;
80			}
81	
82			await this.redisWrite.set(
83				`oauth_state:${state}`,
84				JSON.stringify(stateData),
85				'EX',
86				OAUTH_STATE_TTL,
87			);
88	
89			const strategy = this.getStrategy({ provider });
90			return strategy.createAuthorizationURL({ state, codeVerifier });
91		}
92	
